const providerConfigs = {
  openai: {
    label: 'OpenAI',
    source_name: 'OpenRouter Models API - OpenAI',
    source_url: 'https://openrouter.ai/api/v1/models',
    match: (model) => String(model.id || '').startsWith('openai/'),
  },
  anthropic: {
    label: 'Anthropic',
    source_name: 'OpenRouter Models API - Anthropic',
    source_url: 'https://openrouter.ai/api/v1/models',
    match: (model) => String(model.id || '').startsWith('anthropic/'),
  },
  google: {
    label: 'Google Gemini',
    source_name: 'OpenRouter Models API - Google Gemini',
    source_url: 'https://openrouter.ai/api/v1/models',
    match: (model) => String(model.id || '').startsWith('google/') && /gemini/i.test(String(model.id || '') + ' ' + String(model.name || '')),
  },
};

function normalize(text) {
  return String(text || '').replace(/\s+/g, ' ').trim();
}

function slugify(value) {
  return String(value || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 100);
}

function yamlString(value) {
  const safe = String(value || '').replace(/\\/g, '\\\\').replace(/"/g, '\\"');
  return '"' + safe + '"';
}

function createdDate(model) {
  const created = Number(model.created || 0);
  if (!created) return 'date inconnue';
  return new Date(created * 1000).toISOString().slice(0, 10);
}

const input = $input.first().json;
const models = Array.isArray(input.data) ? input.data : [];
const now = new Date().toISOString();
const datePart = now.slice(0, 10);
const timePart = now.slice(11, 19).replace(/:/g, '');
const outputs = [];

for (const [provider, config] of Object.entries(providerConfigs)) {
  const selected = models.filter(config.match).sort((a, b) => Number(b.created || 0) - Number(a.created || 0)).slice(0, 8);
  const title = 'Latest ' + config.label + ' models snapshot';
  const fileName = datePart + '-' + timePart + '-' + provider + '-latest-models-openrouter-snapshot.md';
  const outputPath = '/vault/raw/passive/model/' + fileName;
  const modelLines = selected.length
    ? selected.map((model) => '- ' + normalize(model.name || model.id) + ' (' + model.id + ', added ' + createdDate(model) + ')')
    : ['- Aucun modele detecte automatiquement.'];
  const excerpt = selected.map((model) => normalize((model.name || model.id) + ' - ' + (model.description || '')).slice(0, 220)).join('\n');
  const markdown = [
    '---',
    'kind: passive-capture',
    'source_name: ' + yamlString(config.source_name),
    'source_type: secondaire',
    'category: model-snapshot',
    'provider: ' + provider,
    'signal_type: model-snapshot',
    'tags: [ia, ' + provider + ', model-snapshot, openrouter]',
    'title: ' + yamlString(title),
    'url: ' + yamlString(config.source_url),
    'published_at: ' + yamlString(now),
    'collected_at: ' + yamlString(now),
    'confidence: medium',
    'major_update: true',
    'workflow: manual-provider-models-snapshot',
    'status: a-traiter',
    '---',
    '',
    '# ' + title,
    '',
    '## Metadonnees',
    '- Provider : ' + provider,
    '- Source : ' + config.source_name,
    '- Type : secondaire',
    '- Categorie : model-snapshot',
    '- URL : ' + config.source_url,
    '- Collecte le : ' + now,
    '',
    '## Modeles detectes',
    ...modelLines,
    '',
    '## Extrait brut',
    excerpt || 'Aucun extrait disponible.',
    '',
    '## Resume IA preliminaire',
    '- Snapshot manuel des derniers modeles visibles sur OpenRouter pour ' + config.label + '.',
    '- Cette capture sert a peupler raw/passive/model/ pour la veille provider.',
    '- OpenRouter est utilise comme agregateur secondaire : verifier les modeles importants contre les docs officielles avant synthese.',
    '',
    '## Points a verifier',
    '- Verifier dans la documentation officielle du provider si ces modeles sont bien les plus recents ou les plus pertinents.',
    '- Decider si une note provider doit etre creee ou mise a jour.',
    '',
    '## Action possible',
    '- [ ] Decider si cette entree merite une mise a jour dans wiki/notes/' + provider + '.md ou wiki/notes/modeles-ia.md',
    ''
  ].join('\n');
  outputs.push({ json: { provider, source_name: config.source_name, title, outputPath, markdown } });
}
return outputs;
